// projectDetailTitle returns the page title: the project name when
// resolved, or a neutral fallback for the empty-state path.
func projectDetailTitle(data ProjectDetailData) string {
	if !data.Found {
		return "Project"
	}
	return data.Name
}

// projectLastActivityLabel returns "—" when there is no last-activity
// timestamp (e.g. a project with zero memories) instead of an empty string.
func projectLastActivityLabel(data ProjectDetailData) string {
	if data.LastActivity == "" {
		return "—"
	}
	return data.LastActivity
}

